const body = $json.body ?? $json;
const clientToken = body.clientToken ?? body.token ?? '';

if (!clientToken) {
  throw new Error('clientToken is required');
}

return [{ json: { clientToken } }];

const row = $json;
const status = row.estado || row.Estado || 'Diagnóstico Capturado';
const normalized = String(status).toLowerCase().trim();

let currentPhase = 'Desarrollo';
let progressPercentage = 0;
if (['diagnóstico capturado', 'diagnostico capturado'].includes(normalized)) {
  currentPhase = 'Descubrimiento';
  progressPercentage = 10;
} else if (normalized === 'brief enviado') {
  currentPhase = 'Descubrimiento';
  progressPercentage = 20;
} else if (normalized === 'brief completado') {
  currentPhase = 'Descubrimiento';
  progressPercentage = 30;
} else if (['cotización en revisión', 'cotizacion en revision'].includes(normalized)) {
  currentPhase = 'Cotización';
  progressPercentage = 35;
} else if (normalized === 'firmado') {
  currentPhase = 'Aprobado Comercial';
  progressPercentage = 50;
} else if (normalized === 'contrato enviado') {
  currentPhase = 'Contratación';
  progressPercentage = 65;
}

const quoteUrl = row.Quote_PDF_URL || '';
const contractUrl = row.Contract_URL || '';
const quoteStatus = row.Quote_Status || (normalized === 'firmado' ? 'Aprobado' : quoteUrl ? 'En revisión' : 'Pendiente');
const documents = [];
if (quoteUrl) {
  documents.push({
    id: row.Quote_Document_Id || `quote-${row.leadId}`,
    name: 'Cotización Comercial',
    type: 'pdf',
    kind: 'quote',
    status: quoteStatus,
    url: quoteUrl,
    updatedAt: row.Quote_Generated_At || ''
  });
}
if (contractUrl) {
  documents.push({
    id: `contract-${row.leadId}`,
    name: 'Contrato Comercial',
    type: 'pdf',
    kind: 'contract',
    status: 'En revisión',
    url: contractUrl,
    updatedAt: row.Contract_Generated_At || ''
  });
}

return [{
  json: {
    clientToken: row.Brief_Token || $('Validate Client Token').item.json.clientToken,
    estado: status,
    projectName: row.empresa || row.nombre || 'Proyecto JS Solutions',
    serviceType: row.servicio || 'Implementación tecnológica',
    currentPhase,
    progressPercentage,
    driveFolderUrl: row.Drive_Folder_URL || row.Drive_Folder_Link || '',
    quote: quoteUrl
      ? {
          id: row.Quote_Document_Id || `quote-${row.leadId}`,
          name: 'Cotización Comercial',
          url: quoteUrl,
          status: quoteStatus,
          sentAt: row.Quote_Generated_At || undefined,
          approvedAt: row.Quote_Approved_At || undefined
        }
      : undefined,
    tasks: [],
    milestones: [],
    documents
  }
}];
